const AWS = require('aws-sdk');
const DynamoDB = new AWS.DynamoDB.DocumentClient();
const SQS = new AWS.SQS();

exports.handler = async (event) => {
  try {
    const order = JSON.parse(event.Records[0].body);
    
    // Validate untrusted input
    if (!order || !order.orderId || !order.customerId || !order.totalAmount) {
      console.error('Invalid order data');
      return;
    }
    
    // Call external payment API (using a secure library like Axios)
    const axios = require('axios');
    const response = await axios.post('https://payment-api.com/process-order', order);
    
    if (response.status !== 200) {
      console.error(`Payment processing failed: ${response.statusText}`);
      return;
    }
    
    // Update DynamoDB with payment status
    const params = {
      TableName: 'Orders',
      Key: { orderId: order.orderId },
      UpdateExpression: 'set #status = :status, #paymentStatus = :paymentStatus',
      ExpressionAttributeNames: { '#status': 'status', '#paymentStatus': 'paymentStatus' },
      ExpressionAttributeValues: { ':status': 'processed', ':paymentStatus': response.data.paymentStatus }
    };
    
    await DynamoDB.update(params).promise();
  } catch (error) {
    console.error(error);
  }
};